"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[595],{1814(e,n,t){t.r(n),t.d(n,{assets:()=>h,contentTitle:()=>s,default:()=>c,frontMatter:()=>o,metadata:()=>r,toc:()=>d});var a=t(4848),i=t(8453);const o={},s="Chapter 2: Welcome to Mist Valley",r={id:"mirror-realm/ch02",title:"Chapter 2: Welcome to Mist Valley",description:"Taiwan Edition v5",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/mirror-realm/ch02.md",sourceDirName:"mirror-realm",slug:"/mirror-realm/ch02",permalink:"/MythogenEngine/en/docs/mirror-realm/ch02",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 1: The Least Worst Choice",permalink:"/MythogenEngine/en/docs/mirror-realm/ch01"},next:{title:"Chapter 3: The Cost of QCC",permalink:"/MythogenEngine/en/docs/mirror-realm/ch03"}},h={},d=[{value:"Taiwan Edition v5",id:"taiwan-edition-v5",level:3}];function l(e){const n={code:"code",em:"em",h1:"h1",h3:"h3",header:"header",hr:"hr",p:"p",pre:"pre",...(0,i.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"chapter-2-welcome-to-mist-valley",children:"Chapter 2: Welcome to Mist Valley"})}),"\n",(0,a.jsx)(n.h3,{id:"taiwan-edition-v5",children:"Taiwan Edition v5"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"Location: Mirror Realm \xb7 Emerald Isle (Parallel Universe No. 15)\nTime: JUN 1021 (4 years, 8 months ago)\nProtagonist: Lin Zhao-ming"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"The offer was signed, and he flew to Emerald Isle."}),"\n",(0,a.jsx)(n.p,{children:"Off the plane, straight into quarantine. Fourteen days mandatory plus seven days self-monitoring, stuck in a hotel room, unable to go out."}),"\n",(0,a.jsx)(n.p,{children:"He didn't think it was miserable."}),"\n",(0,a.jsx)(n.p,{children:"On the third day, a black hard-shell case was delivered. Inside was a Mirror Screen terminal, a docking station, and a company access card\u2014though there was nowhere to swipe it, because he wasn't even at the company. There was also an A4 piece of paper: Rule number one, please log in to the company intranet."}),"\n",(0,a.jsx)(n.p,{children:"He sat on the edge of the hotel bed, powered it on, and logged in."}),"\n",(0,a.jsx)(n.p,{children:"There was an invitation on his calendar: Welcome Call, 3:00 PM. The organizer was Peter Legacy, and there were eight participants, none of whose names he recognized."}),"\n",(0,a.jsx)(n.p,{children:"He didn't find it strange. The company was operating as usual, he just hadn't arrived on-site yet."}),"\n",(0,a.jsx)(n.p,{children:"Simultaneously, the boss's group chat started showing activity. Meeting notifications came one after another, too many to count. No one specifically asked him to join. He listened in on one or two, felt they were routine matters, and didn't bother following them further. He spent his days eating, playing video games, reading, and occasionally researching the things he was about to be working on."}),"\n",(0,a.jsx)(n.p,{children:"Twenty-one days. Every day, he was his own master."}),"\n",(0,a.jsx)(n.p,{children:"After quarantine ended, there was still a week before his official onboarding. He went for walks around Mist Valley, ate some local food, and checked up on that apartment unit."}),"\n",(0,a.jsx)(n.p,{children:"For nearly a month, every day, he was his own master."}),"\n",(0,a.jsx)(n.p,{children:"Then came his first official day of work. He booted up the Mirror Screen terminal, and the very first notification popped up: Three meetings today."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"One month into the job."}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming had seen the faces of over a dozen people, all exclusively through the Mirror Screen terminal. Faces in little grid boxes, large and small. Some turned their cameras on, others were just a name. Some would smile broadly when they spoke, others would stop talking after exactly three sentences and retreat as if they hadn't opened their mouths at all from the very beginning."}),"\n",(0,a.jsx)(n.p,{children:"He hadn't met a single one of them in person."}),"\n",(0,a.jsx)(n.p,{children:'The benefits of WFH were something Peter had specifically brought up in a monthly review\u2014"Aura Synthesis highly values work-life balance, and WFH is already a core part of our company culture." He sounded very serious when he said it, as if he were presenting an achievement that he had poured his blood, sweat, and tears into building. Lin Zhao-ming listened, and didn\'t say anything.'}),"\n",(0,a.jsx)(n.p,{children:"The benefit of WFH is that no one is watching you. With a meeting running in the background, he could listen while reading other documents. If something important came up, he'd pay attention; if it wasn't important, he'd let it slide. Meetings would drag on to the point where you didn't know when they'd stop, but since you didn't have to be anywhere anyway, you just left them on."}),"\n",(0,a.jsx)(n.p,{children:"Routine matters, producing very little, but making you feel very busy."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"On the day of the Welcome Call, Peter Legacy had his camera on. In his fifties, hair impeccably styled, sitting against a backdrop of a completely white wall. There was absolutely nothing on the wall, like a meticulously arranged blank void."}),"\n",(0,a.jsx)(n.p,{children:"\"Welcome aboard, Zhao-ming. You'll start by taking over the consumer product line to get familiar with the operations. If there's anything you don't understand, feel free to ask anytime.\""}),"\n",(0,a.jsx)(n.p,{children:"The consumer product line\u2014mostly maintenance and support. No new projects, borrowing resources from other teams to learn the ropes. Lin Zhao-ming nodded. Place him somewhere where nothing much could go wrong to observe first. He understood."}),"\n",(0,a.jsx)(n.p,{children:"He started asking questions. There was a Mentor, there was patience, and there was always an answer. But every time an answer was given, he found himself right back at square one\u2014only now with a pile of new documents and several new pieces of corporate jargon, yet the actual answer to his question was nowhere to be found within them."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"The jargon was the first wall."}),"\n",(0,a.jsx)(n.p,{children:"It wasn't the kind of wall built to intentionally keep you out. It was the kind of wall where everyone genuinely wanted to tell you what was going on, but the more you listened, the less you understood."}),"\n",(0,a.jsx)(n.p,{children:"The core technology of the Mirror Screen's electronic core wasn't inherently complex. The core had a few basic parameters: charge indicator, charge/discharge status, and battery health. At the companies he had worked at previously, these things had official, standard names\u2014SOC, SOH, Fuel Gauge. You said the words, and everyone knew what they meant without requiring extra explanation. One number, one meaning, crystal clear."}),"\n",(0,a.jsx)(n.p,{children:"But here at Aura Synthesis, identical concepts had an entirely different set of names."}),"\n",(0,a.jsx)(n.p,{children:'In his first week, he heard a term in a meeting: "Phoenix Threshold."'}),"\n",(0,a.jsx)(n.p,{children:"He thought it was some kind of quality standard. It sounded very substantial. But no one explained it. He went and asked his mentor, J."}),"\n",(0,a.jsx)(n.p,{children:"J was very patient: \"It's better if you ask Fai about this one, he's in charge of that line.\""}),"\n",(0,a.jsx)(n.p,{children:"He went and asked Fai. Fai said, \"That's actually a setting on the manufacturer's side, you should ask the supplier's PM, they should have a document for it.\""}),"\n",(0,a.jsx)(n.p,{children:"He sent an email to the supplier's PM. The PM sent back a specification document. Over twenty pages long."}),"\n",(0,a.jsx)(n.p,{children:'The first three pages were version histories and approval signatures. Pages four through eight were the "Background Explanation," written in a highly professional tone, detailing a bunch of things that, after reading, left him feeling no more enlightened than before. Pages nine to thirteen were an "Overview of Relevant Parameters," listing more than twenty different values. Each one came with two paragraphs of explanation, and after reading those explanations, he still had no idea what the value actually represented in practical operation.'}),"\n",(0,a.jsx)(n.p,{children:"Page fourteen. A table."}),"\n",(0,a.jsx)(n.p,{children:'"Phoenix Threshold."'}),"\n",(0,a.jsx)(n.p,{children:"Definition: The critical threshold value at which the system automatically cuts off the power supply when the electronic core discharges to a specific percentage."}),"\n",(0,a.jsx)(n.p,{children:"He stared at that line of text."}),"\n",(0,a.jsx)(n.p,{children:"In other words, a cut-off percentage."}),"\n",(0,a.jsx)(n.p,{children:"In other words, at what percent battery the device automatically shuts down."}),"\n",(0,a.jsx)(n.p,{children:'This exact thing was called a "shutdown threshold" when he worked at the American company. Two English words, universally understood. In industry spec sheets, this number was usually written on the very first page because it was so fundamental.'}),"\n",(0,a.jsx)(n.p,{children:"But here, from the time he heard the name, to asking the first person, to being pointed to a second person, to being pointed to a third person, to finding this document, to flipping past thirteen pages of professionally packaged nonsense, to finally reaching page fourteen\u2014it took him three days."}),"\n",(0,a.jsx)(n.p,{children:"Three days to find a cut-off percentage."}),"\n",(0,a.jsx)(n.p,{children:"He sat there, looking at the document, a sentence sitting in his heart that he didn't say out loud."}),"\n",(0,a.jsx)(n.p,{children:'Then he kept reading. Because there were over a dozen other names in that document\u2014 "Sirius Steady-State," "Dragon Return Ratio," "Zenith Gradient" \u2014and every single one of them was exactly the same: a perfectly normal technical concept shoved into an obscure name whose meaning you could never guess, wrapped in a dozen pages of paper. Ninety percent of it was "professional explanation" that wouldn\'t make you understand anything more, and the remaining ten percent were the two actual words you needed.'}),"\n",(0,a.jsx)(n.p,{children:'He had asked J once: "Why are these things named like this? Is there a complete glossary anywhere?"'}),"\n",(0,a.jsx)(n.p,{children:"J laughed a little. \"There's no official glossary. But you'll understand once you've been here long enough. Each product line has its own set of terms. Some of them were brought over from when people used to work at that local manufacturing plant.\""}),"\n",(0,a.jsx)(n.p,{children:"Brought over."}),"\n",(0,a.jsx)(n.p,{children:'Meaning, Aura Synthesis hadn\'t invented these names. It was simply that a specific group of people were used to using them at their old company, and brought them over to keep using them here. To them, "Phoenix Threshold" was as natural as "shutdown threshold." It wasn\'t that they were intentionally not explaining it\u2014it was that they fundamentally felt no need to explain. To them, a name was just a name, just like you wouldn\'t bother explaining to a new colleague why a "cup" is called a "cup."'}),"\n",(0,a.jsx)(n.p,{children:"But to Lin Zhao-ming, every single name was a wall he had to climb over. And every time he climbed over a wall and saw what was behind it, he wanted to curse\u2014because the thing itself was simple. The complexity never lay in the thing itself. The complexity was in the packaging."}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming didn't make a fuss. If the jargon was annoying, it was annoying; he'd just learn it. It didn't matter. He thought that once he'd learned it, everything would be fine."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"On the day of that Welcome Call, Lin Zhao-ming couldn't see the boundaries linking those eight names."}),"\n",(0,a.jsx)(n.p,{children:'Several of them had worked together at the same local system manufacturing plant before joining Aura Synthesis. Even further back, some were from the same university department\u2014different graduating classes, but sharing the same professors, the same network of connections, and the same set of unwritten rules about "how to survive in a place like this." This network had never been spoken of out loud\u2014not out of deliberate concealment, but because there was no need to speak of it. Everybody already knew.'}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming was an outsider crammed into the middle of it. But he didn't know that."}),"\n",(0,a.jsx)(n.p,{children:"He just thought he was a newcomer who had arrived a little late."}),"\n",(0,a.jsx)(n.p,{children:'Once, during a meeting discussing vendor shipments, a guy named Old Xu said, "This pattern is exactly the same as when we were at that plant."'}),"\n",(0,a.jsx)(n.p,{children:"The plant he named was a local system manufacturer. Lin Zhao-ming knew of the company\u2014he had seen it when doing his homework."}),"\n",(0,a.jsx)(n.p,{children:"He didn't pay much attention to it at the time. Only later did he piece it together: Old Xu, Fai, Cindy, and a few others had all worked at that local plant before coming to Aura Synthesis. And before that, several of them had come from the same university."}),"\n",(0,a.jsx)(n.p,{children:"This network was never mentioned. It wasn't deliberately hidden\u2014later, he reasoned it was probably just that they felt no need to mention it. Because to them, these facts were known realities, as natural as the weather. You don't explain to a new colleague that \"it rains here.\""}),"\n",(0,a.jsx)(n.p,{children:"But Lin Zhao-ming wasn't from here. He didn't have those dozen or so years of shared history. When he stepped onto the board, the chessboard was already set, the pieces were already in their respective positions, and he was just a new piece placed on the edge. He thought the game had yet to begin. In reality, multiple rounds had already been played long before he even walked in."}),"\n",(0,a.jsx)(n.p,{children:"He just didn't know it."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"One day, Fai stayed behind after a meeting. Everyone else had left, leaving just the two of them."}),"\n",(0,a.jsx)(n.p,{children:'Fai asked, "Zhao-ming, when are you handing in the tracking report for your consumer product line?"'}),"\n",(0,a.jsx)(n.p,{children:'Lin Zhao-ming looked at him. "I haven\'t received that assignment."'}),"\n",(0,a.jsx)(n.p,{children:'Fai chuckled. "Peter probably forgot to CC you. I\'ll forward it to you."'}),"\n",(0,a.jsx)(n.p,{children:"He forwarded it, then logged off. A few seconds later, his grid box went black."}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming opened the email. The date was four days ago. His name wasn't in the recipient list. He looked at the string of recipients: Fai, Cindy, K, Old Xu, and a few other people whose names he recognized but hadn't spoken to."}),"\n",(0,a.jsx)(n.p,{children:"Peter's name was in there. His name was not."}),"\n",(0,a.jsx)(n.p,{children:"He started typing to ask Peter. Typed two lines, deleted them. Typed another line, deleted it again."}),"\n",(0,a.jsx)(n.p,{children:"Finally, he just started working on the report."}),"\n",(0,a.jsx)(n.p,{children:"Four days of missed time, he made up for it in two. When he handed it to Peter, Peter said, \"Good work, keep it up.\" He didn't mention that Lin Zhao-ming was four days late. He didn't mention that absolutely no one had notified him to begin with."}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming thought it was an accident. Forgetting to CC someone happens everywhere."}),"\n",(0,a.jsx)(n.p,{children:'Only later did he realize that this kind of "forgetting" followed a pattern. But at the time, he didn\'t know how to read the patterns yet.'}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"He merely noticed something strange: The data was all there. Inside the system, the documents were complete, the records were complete, the histories were complete, everything looked transparent and intact. But it didn't match the facts. It wasn't that there was no data; it was that the data told you one story, while the actual reality of what happened was another story entirely. What was missing in between, he couldn't find anywhere."}),"\n",(0,a.jsx)(n.p,{children:"He thought it was just because he wasn't familiar enough yet."}),"\n",(0,a.jsx)(n.p,{children:'One day, Old Xu answered a question of his by saying, "Take a look on ALC, it should be there."'}),"\n",(0,a.jsx)(n.p,{children:"ALC."}),"\n",(0,a.jsx)(n.p,{children:'These three letters. He had heard them once before. During his first week, when J was explaining the system architecture, he had mentioned it, casually, as naturally as saying "just open your browser."'}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming logged into ALC."}),"\n",(0,a.jsx)(n.p,{children:"His very first feeling was: Wow."}),"\n",(0,a.jsx)(n.p,{children:"The interface was clean, the structure was clear. On the left was the navigation panel, categorized into classes\u2014Product Lines, Vendors, Test Records, Quality Reports, Personnel Structure, Process Documents. Inside each category were subfolders, and inside those subfolders were more subfolders. The sheer volume of documents was oceanic. He casually clicked one open with his mouse: Product Lines > Mirror Screen Terminal > Electronic Core > Supplier Evaluation. Inside were over twenty files, each marked with a date, version number, and an assigned owner."}),"\n",(0,a.jsx)(n.p,{children:"He clicked on another: Test Records > Q2 1021 > Functional Testing. Dozens of log files, each with timestamps, test conditions, and a result summary."}),"\n",(0,a.jsx)(n.p,{children:"It looked as though everything was perfectly transparent."}),"\n",(0,a.jsx)(n.p,{children:'He selected a quality report and opened it. Over forty pages. Complete with charts, exhaustive data, and clear conclusions\u2014"Supplier component anomaly rates remain within acceptable bounds; continuous monitoring is advised."'}),"\n",(0,a.jsx)(n.p,{children:'He selected another. Thirty pages. Same structure, same tone. Different data, but the exact same conclusion\u2014"acceptable bounds," "continuous monitoring."'}),"\n",(0,a.jsx)(n.p,{children:"He selected a third."}),"\n",(0,a.jsx)(n.p,{children:"The data in the third report contradicted the first two. Not a massive contradiction, a minor one\u2014Q1 stated the yield rate was a certain number, and Q2 stated the yield rate had improved, but he ran the math: if the Q1 number was genuine, the magnitude of improvement claimed in Q2 didn't mathematically align with actual output. The gap was incredibly small, so small that if you only looked at one report, you'd never notice. You had to lay all three out side-by-side to see it."}),"\n",(0,a.jsx)(n.p,{children:"He paused."}),"\n",(0,a.jsx)(n.p,{children:"What did this mean? A typo from typing too fast? Differing statistical parameters? Or..."}),"\n",(0,a.jsx)(n.p,{children:"He didn't continue the thought. He assumed he just wasn't familiar enough with how this system calculated its metrics yet. Every company has its own way of doing things\u2014definitions of numbers, sampling methods, the internal logic of their reporting. He was still in the learning phase."}),"\n",(0,a.jsx)(n.p,{children:"He closed the report and continued reading documents."}),"\n",(0,a.jsx)(n.p,{children:"ALC's tutorial files were exceptionally well-made. Every single function had step-by-step instructions, complete with screenshots and FAQs. He spent two hours walking through it from start to finish."}),"\n",(0,a.jsx)(n.p,{children:"Once he finished, he knew how to use the system. He knew where to find reports, where to look at test records, where to check supplier evaluations."}),"\n",(0,a.jsx)(n.p,{children:"He just thought: This system is pretty easy to use. The data is comprehensive. As long as I keep reading, sooner or later, I'll figure it out."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"On a Wednesday afternoon, there was a project synchronization meeting. Eight people. Lin Zhao-ming was the ninth."}),"\n",(0,a.jsx)(n.p,{children:"Halfway through the meeting, they touched upon an issue with a part specification. Fai said he had contacted the manufacturer, and the manufacturer said they needed time to confirm. Cindy said she had handled a similar case before and could share her experience. Old Xu said the schedule waits for no man, and they needed to push harder."}),"\n",(0,a.jsx)(n.p,{children:"The conversation between the three of them was fast, precise, with no gaps in between. Fast as if it had been rehearsed. But it didn't feel rehearsed\u2014it felt genuinely natural. The kind of natural that only comes when you've done something so many times that your body simply remembers the rhythm."}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming sat there listening."}),"\n",(0,a.jsx)(n.p,{children:"He suddenly realized something: The conversation these three people were having didn't start in this meeting. It had already started before the meeting even began. They were just performing it here, for the others to see."}),"\n",(0,a.jsx)(n.p,{children:"He didn't have any evidence. Just a feeling. But that feeling was sharp and clear."}),"\n",(0,a.jsx)(n.p,{children:'When the meeting ended, he wanted to ask J: "Did they already discuss this before the meeting?"'}),"\n",(0,a.jsx)(n.p,{children:"He typed a few words. Deleted them."}),"\n",(0,a.jsx)(n.p,{children:"What would asking that question mean? It meant he believed people were doing things behind the scenes. But he had no proof. He was just a newcomer who felt some things didn't seem entirely natural. If he said it out loud, what would the other side think?"}),"\n",(0,a.jsx)(n.p,{children:'"This new guy is too paranoid."'}),"\n",(0,a.jsx)(n.p,{children:"He didn't ask."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"A few more days passed."}),"\n",(0,a.jsx)(n.p,{children:"A video conference ended, and the grid boxes on the screen went black one by one. Some people logged off immediately, others stayed behind. Leaving the call open like this was natural\u2014the meeting was over, you chat for a bit, just like talking in the hallway after class before heading home."}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming stayed behind too. He didn't log off, because he wanted to listen in."}),"\n",(0,a.jsx)(n.p,{children:"Four people remained: Him, Cindy, K, and a back-end engineer named Xiao Hu."}),"\n",(0,a.jsx)(n.p,{children:"K was talking about his son's school, and Xiao Hu was smiling and listening. Cindy, off to the side, suddenly said, \"I'm so exhausted lately. Rent in Emerald City went up again. Can't hold on much longer.\""}),"\n",(0,a.jsx)(n.p,{children:"Emerald City. She was talking about the capital of Emerald Isle. Most people who worked here rented apartments there."}),"\n",(0,a.jsx)(n.p,{children:'Hearing this, Lin Zhao-ming said casually, "Well, since you\'re WFH right now, why not just move back to your hometown?"'}),"\n",(0,a.jsx)(n.p,{children:"Dead silence."}),"\n",(0,a.jsx)(n.p,{children:"The kind of obvious, air-solidifying dead silence. It only lasted two seconds, but that was long enough."}),"\n",(0,a.jsx)(n.p,{children:'Cindy gave a short laugh and said, "My hometown is in Lu Township."'}),"\n",(0,a.jsx)(n.p,{children:"Then K very quickly picked right back up, shifting to another topic. Xiao Hu chimed in as well. The air thawed out."}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming continued to sit there, staring at the screen."}),"\n",(0,a.jsx)(n.p,{children:'He didn\'t understand the underlying meaning behind those words, "My hometown is in Lu Township."'}),"\n",(0,a.jsx)(n.p,{children:"He knew Lu Township was located in the south of Emerald Isle. He knew that for WFH, living in the north or south theoretically made zero difference. He knew rent in Emerald City was expensive. He knew that if you could save money, moving back to your hometown was the perfectly normal choice."}),"\n",(0,a.jsx)(n.p,{children:"But the moment he asked, the air froze. Which meant that this choice was not normal."}),"\n",(0,a.jsx)(n.p,{children:"He had definitely stepped on a landmine. He just didn't know what it was."}),"\n",(0,a.jsx)(n.p,{children:"He thought about it for a long time. Was staying in Emerald City a matter of convenience? No, WFH doesn't require commuting convenience. Was it about lifestyle? Lu Township has a lifestyle too. Was it because..."}),"\n",(0,a.jsx)(n.p,{children:"He couldn't think of it. He didn't have this specific tool in his toolkit."}),"\n",(0,a.jsx)(n.p,{children:"On Intermediary Island, geography was purely functional\u2014you lived where you did because of where you went to work. You moved because you changed jobs. No other reasons were required."}),"\n",(0,a.jsx)(n.p,{children:"But on Emerald Isle, maybe geography wasn't just functional. Maybe geography was... he couldn't find the word. Status? Belonging? A membership card?"}),"\n",(0,a.jsx)(n.p,{children:"He didn't know. He only knew he had stepped on something, and he couldn't say the name of the thing he had stepped on."}),"\n",(0,a.jsx)(n.p,{children:"When he saw Cindy later, her attitude toward him hadn't changed at all. Normal politeness, normal distance. He wasn't sure if that incident had lingered between them. Maybe it did. Maybe it didn't. Maybe he was the only one holding onto it."}),"\n",(0,a.jsx)(n.p,{children:"He didn't ask again."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"One day, K privately messaged him on Teams."}),"\n",(0,a.jsx)(n.p,{children:'It wasn\'t official business. No subject line, no attachments, just a few typed words: "Zhao-ming, does your wife work on Emerald Isle or Intermediary Island?"'}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming replied. Intermediary Island, fully remote."}),"\n",(0,a.jsx)(n.p,{children:'"Oh, well that\'s convenient then," K said. "What district do you guys live in? Renting or buying?"'}),"\n",(0,a.jsx)(n.p,{children:"He replied again. Bought a place. Mist Valley."}),"\n",(0,a.jsx)(n.p,{children:'K sent over a huge wall of text. Talked all about himself\u2014his twins were starting elementary school this year, the cost of international school tuition, how much car loan he had left. He had run the numbers; if he got laid off, he\'d be in serious trouble within three months. "Everyone is under a lot of pressure," he said.'}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming didn't know how to respond to that. He owned his house, he had no rent pressure, he hadn't taken out a loan to buy a car, he didn't have kids to put through international school. His pressure was completely different\u2014the living expenses for two elderly parents back on Intermediary Island could never stop. But that kind of pressure had no place in this conversation."}),"\n",(0,a.jsx)(n.p,{children:'He typed a single sentence: "I understand. It\'s tough."'}),"\n",(0,a.jsx)(n.p,{children:'K replied: "Let\'s grab a drink sometime."'}),"\n",(0,a.jsx)(n.p,{children:"And then it was over."}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming thought it was just idle workplace chatter. Colleagues talking about their personal situations; totally normal."}),"\n",(0,a.jsx)(n.p,{children:"He didn't know that within that very same week, K had chatted with every other person on the team about almost the exact same content. Every conversation was one-on-one. And every person thought it was just normal idle chatter."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"The days went by quickly. Every day: boot up, go to meetings, read documents, do work, shut down."}),"\n",(0,a.jsx)(n.p,{children:"He began to adapt to the rhythm. Or, more accurately, he began to grow numb to it. The content of the meetings didn't all need to be heard\u2014he had figured out what was important and what wasn't. He had figured out whose words actually contained substance and whose didn't. He started getting a feel for which decisions were real and which were just putting on a show."}),"\n",(0,a.jsx)(n.p,{children:'But he found himself in a very strange position: He could see a great many things, but his "visibility" had absolutely zero impact on anything.'}),"\n",(0,a.jsx)(n.p,{children:"It was like being separated by a sheet of glass. You can see the people on the other side doing their work, and you know exactly what they're doing, but you can't touch it, you can't intervene. You just watch."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"Peter reached out to him twice that month."}),"\n",(0,a.jsx)(n.p,{children:'The first was a routine one-on-one. Peter had his camera on, backed by that blank white wall, as pristine as a room no one had ever lived in. He asked Lin Zhao-ming, "How are you adjusting?"'}),"\n",(0,a.jsx)(n.p,{children:'"Alright. The documentation is heavy, but I\'m slowly digesting it."'}),"\n",(0,a.jsx)(n.p,{children:'"Good. Take your time, there\'s no rush. The pace of the consumer product line is slower, it gives you time to adapt."'}),"\n",(0,a.jsx)(n.p,{children:"Peter's tone of voice was always flat. Not cold, not warm, just... a constant temperature. Exactly like an office permanently kept at 23 degrees Celsius. Comfortable, but you can never feel the seasons change."}),"\n",(0,a.jsx)(n.p,{children:'"Is there anything you want to know more about?" Peter asked.'}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming thought for a second. He wanted to ask: Have the people on this team known each other for a long time? He wanted to ask: Are those tiny discrepancies in the ALC reports normal? He wanted to ask: Why are there some meetings that I'm not CC'd on?"}),"\n",(0,a.jsx)(n.p,{children:"He didn't ask. It wasn't that he lacked the courage. It was because he felt that declaring \"I think something isn't right here\" in your very first month felt like... a newcomer questioning things before even understanding the baseline situation wasn't a show of competence, it was a display of \"not knowing how to handle social politics.\""}),"\n",(0,a.jsx)(n.p,{children:'"Nothing for now," he said. "Thank you."'}),"\n",(0,a.jsx)(n.p,{children:'Peter nodded. "Alright. Keep the communication lines open."'}),"\n",(0,a.jsx)(n.p,{children:"The second time was because of an email from a vendor. The vendor had asked a technical question, CC'ing both Peter and Lin Zhao-ming. Lin Zhao-ming felt he could answer it, so he just directly replied."}),"\n",(0,a.jsx)(n.p,{children:'Peter called him afterward: "Zhao-ming, next time, before you reply to that vendor, let me know first."'}),"\n",(0,a.jsx)(n.p,{children:"There was no unhappiness in the tone. It was just a factual directive."}),"\n",(0,a.jsx)(n.p,{children:'"Was there an issue with the content of my reply?" Lin Zhao-ming asked.'}),"\n",(0,a.jsx)(n.p,{children:'"No. Technically, there was no issue. But this particular vendor is a bit sensitive. There is some background to their cases that you don\'t fully understand yet. Next time, verify with me first."'}),"\n",(0,a.jsx)(n.p,{children:"Lin Zhao-ming said okay."}),"\n",(0,a.jsx)(n.p,{children:"After hanging up the phone, he thought: What background?"}),"\n",(0,a.jsx)(n.p,{children:"He opened ALC and searched the vendor's name. Over a dozen documents popped up. He read them one by one. Historical correspondence, quality evaluations, meeting minutes. The data was perfectly complete; after reading it, he knew the vendor's supply history, quality trends, and primary contacts."}),"\n",(0,a.jsx)(n.p,{children:'But he couldn\'t find the "background" Peter was talking about.'}),"\n",(0,a.jsx)(n.p,{children:"There was a massive crack running down the center between what the data told him and what Peter's words had implied. He could see both sides of the crack, but he couldn't see what lay inside it."}),"\n",(0,a.jsx)(n.p,{children:"Once again, he just assumed he wasn't familiar enough yet."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"At the end of his first month, Lin Zhao-ming conducted a self-review."}),"\n",(0,a.jsx)(n.p,{children:"He wrote it down in a private document, shown to no one:"}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{children:"Things I've learned:\n- Product line architecture\n- Basic vendor situations\n- ALC system operations\n- Team members' names and general roles\n\nThings I still don't understand:\n- Why some meetings relevant to me aren't CC'd to me\n- What those tiny discrepancies in ALC's reports represent\n- What the \"background\" Peter mentioned actually is\n- The true decision-making logic of this team\n\nActions:\n- Keep learning\n- Don't rush\n- Adapt\n"})}),"\n",(0,a.jsx)(n.p,{children:'He looked at those two words: "Keep learning."'}),"\n",(0,a.jsx)(n.p,{children:"He assumed time could solve these problems. He assumed that as long as he was patient enough, worked hard enough, and paid close enough attention, one day he would perfectly understand it all."}),"\n",(0,a.jsx)(n.p,{children:"This conviction was something he had brought with him from Intermediary Island. At the companies on Intermediary Island, and at the American company, this conviction held entirely true. Time really did fix a lot of things. If you did an exceptionally good job, others naturally respected you. If you understood the work deeply enough, a space was naturally made for you."}),"\n",(0,a.jsx)(n.p,{children:"He didn't know that the rules of the game on Emerald Isle were entirely different."}),"\n",(0,a.jsx)(n.p,{children:'He just sat in his study, closed his laptop, and felt that his first month had been "reasonably smooth."'}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"Location: Mirror Realm \xb7 Emerald Isle Study (Parallel Universe No. 15)\nTime: AUG 1021 (4 years, 6 months ago)\nLate at night"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"That night, he was in the study, and his wife was in the living room. Same floor, but they were used to this\u2014he would usually sit in the study for a while after clocking out, waiting until she came out before exchanging a few words."}),"\n",(0,a.jsx)(n.p,{children:'"My first month is over," he said.'}),"\n",(0,a.jsx)(n.p,{children:'"Yeah. How does it feel?" his wife walked over and stood in the doorway of the study.'}),"\n",(0,a.jsx)(n.p,{children:'He leaned back in his chair and thought for a moment. "The colleagues seem okay. But... it\'s very hard to truly get to know them."'}),"\n",(0,a.jsx)(n.p,{children:'"Well, with WFH, of course it\'s different," she said. "Take your time."'}),"\n",(0,a.jsx)(n.p,{children:"He hummed in agreement."}),"\n",(0,a.jsx)(n.p,{children:"He wanted to say a bit more. Wanted to say that he felt like this group of people had already known each other for a very long time, but no one was telling him. Wanted to mention the ALC reports, and how there were microscopic details that he couldn't mathematically align. Wanted to talk about that meeting he stumbled into, and that one dead second of frozen air."}),"\n",(0,a.jsx)(n.p,{children:"But the words wouldn't leave his mouth. Not because he didn't trust his wife. But because if he said them out loud, it would sound like: \"I'm already getting paranoid in my very first month.\""}),"\n",(0,a.jsx)(n.p,{children:"He didn't want to be that. He wanted to believe his judgments were just the hyper-sensitivity of a newcomer. A few months, and it would be fine. Once he adapted, it would be fine."}),"\n",(0,a.jsx)(n.p,{children:'"Want something to drink?" his wife asked.'}),"\n",(0,a.jsx)(n.p,{children:'"Sure."'}),"\n",(0,a.jsx)(n.p,{children:"His wife went into the kitchen, and he stayed in the study."}),"\n",(0,a.jsx)(n.p,{children:"He stared at that powered-down screen. When the screen was black, it reflected the contours of the study\u2014the bookshelf on the wall, the cup on the desk, his own shadow."}),"\n",(0,a.jsx)(n.p,{children:"Blurry. Like he could see it, but also like he couldn't see it at all."}),"\n",(0,a.jsx)(n.p,{children:"He walked out. Took the cup from her, took a sip."}),"\n",(0,a.jsx)(n.p,{children:'"Emerald Isle is very quiet," he said.'}),"\n",(0,a.jsx)(n.p,{children:'His wife looked at him. "What\'s wrong?"'}),"\n",(0,a.jsx)(n.p,{children:'"The nights are very quiet," he said. "Sometimes I feel... like I\'m the only person around."'}),"\n",(0,a.jsx)(n.p,{children:"He didn't tell her that he wasn't really talking about Emerald Isle."}),"\n",(0,a.jsx)(n.p,{children:"He didn't say he was talking about being in a team with a dozen people, having three or four meetings a day, receiving dozens of emails a day, yet not a single thing making him feel like he was actually there."}),"\n",(0,a.jsx)(n.p,{children:"He didn't say it. Because he still wasn't sure if that feeling was real, or if it was just his own problem."}),"\n",(0,a.jsx)(n.p,{children:"They each finished their drinks, and each went to sleep."}),"\n",(0,a.jsx)(n.p,{children:"The night on Emerald Isle was truly quiet."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.em,{children:"He thought he had entered the field. In reality, he was standing on a chessboard with invisible boundaries. The pieces were already set. The game had already begun. And he still thought he was sitting in the audience."})})]})}function c(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},8453(e,n,t){t.d(n,{R:()=>s,x:()=>r});var a=t(6540);const i={},o=a.createContext(i);function s(e){const n=a.useContext(o);return a.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),a.createElement(o.Provider,{value:n},e.children)}}}]);